                                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                                    <input type="tel" class="form-control" value="@r.Phone"
                                           @onchange="e => UpdateRef(idx, r with { Phone = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                        </div>
                    </div>
                }
                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddReference">
                        + Add Reference
                    </button>
                }
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => GoToStep(2)">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromStep3">Next</button>
                </div>
            </div>
        }

        @* ── Step 4: Cover Letter ── *@
        @if (_currentStep == 4)
        {
            <div>
                <h4 class="mb-3">Cover Letter</h4>
                <div class="mb-2">
                    <textarea class="form-control" rows="10" maxlength="2000"
                              @bind="_coverLetter" @bind:event="oninput"></textarea>
                </div>
                <div class="text-muted small mb-3">@_coverLetter.Length / 2000 characters</div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => GoToStep(3)">Back</button>
                    <button class="btn btn-primary" @onclick="() => GoToStep(5)">Next</button>
                </div>
            </div>
        }

        @* ── Step 5: Review & Submit ── *@
        @if (_currentStep == 5)
        {
            <div>
                <h4 class="mb-3">Review &amp; Submit</h4>

                @* Personal Info Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Personal Information</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    <div class="card-body">
                        <div class="row">
                            <div class="col-md-6"><strong>Name:</strong> @_fullName</div>
                            <div class="col-md-6"><strong>Email:</strong> @_email</div>
                            <div class="col-md-6 mt-1"><strong>Phone:</strong> @_phone</div>
                            <div class="col-md-6 mt-1"><strong>Address:</strong> @_address</div>
                        </div>
                    </div>
                </div>

                @* Work History Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Work History</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    <div class="card-body">
                        @foreach (var entry in _workEntries)
                        {
                            <div class="mb-2 @(entry != _workEntries[0] ? "border-top pt-2" : "")">
                                <div><strong>@entry.Title</strong> at @entry.Company</div>
                                <div class="text-muted small">
                                    @entry.StartDate.ToString("MMM yyyy") &ndash;
                                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                                </div>
                                @if (!string.IsNullOrWhiteSpace(entry.Description))
                                {
                                    <div class="small mt-1">@entry.Description</div>
                                }
                            </div>
                        }
                    </div>
                </div>

                @* References Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>References</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <div class="card-body">
                        @foreach (var r in _references)
                        {
                            <div class="mb-2 @(r != _references[0] ? "border-top pt-2" : "")">
                                <div><strong>@r.Name</strong> (@r.Relationship)</div>
                                <div class="text-muted small">@r.Email &middot; @r.Phone</div>
                            </div>
                        }
                    </div>
                </div>

                @* Cover Letter Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Cover Letter</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(4)">Edit</button>
                    </div>
                    <div class="card-body">
                        <p style="white-space: pre-wrap;">@_coverLetter</p>
                    </div>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => GoToStep(4)">Back</button>
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_submitting">
                        @if (_submitting)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Submit Application
                    </button>
                </div>
            </div>
        }
    }
</div>

@code {
    private static readonly string[] _stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep = 1;
    private string _errorMessage = string.Empty;
    private bool _submitted;
    private int _applicationId;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;
    private string _emailError = string.Empty;
    private bool _validating;

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<ReferenceModel> _references = [new()];

    // Step 4
    private string _coverLetter = string.Empty;

    // Step 5
    private bool _submitting;

    // ── Navigation ──

    private void GoToStep(int step)
    {
        _errorMessage = string.Empty;
        _emailError = string.Empty;
        _currentStep = step;
    }

    // ── Step 1 ──

    private async Task NextFromStep1()
    {
        _errorMessage = string.Empty;
        _emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _validating = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email.Trim());
            if (!valid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            _validating = false;
        }

        _currentStep = 2;
    }

    // ── Step 2 ──

    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index) => _workEntries.RemoveAt(index);

    private void UpdateWork(int index, WorkEntryModel updated) => _workEntries[index] = updated;

    private void NextFromStep2()
    {
        _errorMessage = string.Empty;
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
                || e.StartDate == default)
            {
                _errorMessage = "Please fill in company, title, and start date for every position.";
                return;
            }
        }
        _currentStep = 3;
    }

    // ── Step 3 ──

    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index) => _references.RemoveAt(index);

    private void UpdateRef(int index, ReferenceModel updated) => _references[index] = updated;

    private void NextFromStep3()
    {
        _errorMessage = string.Empty;
        if (_references.Count < 2)
        {
            _errorMessage = "Please provide at least 2 references.";
            return;
        }
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all fields for every reference.";
                return;
            }
        }
        _currentStep = 4;
    }

    // ── Step 5 Submit ──

    private async Task SubmitApplication()
    {
        _errorMessage = string.Empty;
        _submitting = true;
        try
        {
            var personal = new PersonalInfo(_fullName.Trim(), _email.Trim(), _phone.Trim(), _address.Trim());
            var work = new WorkHistory(_workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList());
            var refs = _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var app = new JobApplication(personal, work, refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(app);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }

    // ── Mutable models for form binding ──

    private record WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private record ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

