{"file_text": "@page "/apply"
@rendermode InteractiveServer
@using sv_6faaf404e8e14f648badd9e6b0350bf2.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ── Step Indicator Bar ── *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        @for (int i = 0; i < _stepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = step < _currentStep;
            var isCurrent = step == _currentStep;
            var isFuture = step > _currentStep;
            var clickable = isCompleted && !_submitted;

            <button type="button"
                    class="btn btn-link text-decoration-none p-0 d-flex flex-column align-items-center flex-fill @(isFuture ? "opacity-50" : "")"
                    style="border: none; background: none;"
                    disabled="@(!clickable)"
                    @onclick="() => GoToStep(step)">
                <span class="rounded-circle d-flex align-items-center justify-content-center mb-1"
                      style="width: 36px; height: 36px;
                             background: @(isCurrent ? "#0d6efd" : isCompleted ? "#198754" : "#dee2e6");
                             color: @(isCurrent || isCompleted ? "white" : "#6c757d");
                             font-weight: 600; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </span>
                <small class="@(isCurrent ? "fw-bold" : "") text-center" style="font-size: 0.75rem; color: @(isFuture ? "#adb5bd" : "#212529");">
                    @_stepNames[i]
                </small>
            </button>
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger py-2">@_errorMessage</div>
    }

    @if (_submitted)
    {
        @* ── Confirmation ── *@
        <div class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem; color: #198754;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="text-muted">Your application ID is <strong>@_applicationId</strong>.</p>
            <p class="text-muted">We'll be in touch soon.</p>
        </div>
    }
    else
    {
        @* ── Step 1: Personal Info ── *@
        @if (_currentStep == 1)
        {
            <div>
                <h4 class="mb-3">Personal Information</h4>
                <div class="mb-3">
                    <label class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="_fullName" @bind:event="oninput" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="_email" @bind:event="oninput" />
                    @if (!string.IsNullOrEmpty(_emailError))
                    {
                        <div class="text-danger mt-1 small">@_emailError</div>
                    }
                </div>
                <div class="mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="_phone" @bind:event="oninput" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea class="form-control" rows="2" @bind="_address" @bind:event="oninput"></textarea>
                </div>
                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextFromStep1" disabled="@_validating">
                        @if (_validating)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Next
                    </button>
                </div>
            </div>
        }

        @* ── Step 2: Work History ── *@
        @if (_currentStep == 2)
        {
            <div>
                <h4 class="mb-3">Work History</h4>
                @for (int i = 0; i < _workEntries.Count; i++)
                {
                    var idx = i;
                    var entry = _workEntries[idx];
                    <div class="card mb-3">
                        <div class="card-body">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Position @(idx + 1)</h6>
                                @if (_workEntries.Count > 1)
                                {
                                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                                }
                            </div>
                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Company <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@entry.Company"
                                           @onchange="e => UpdateWork(idx, entry with { Company = (string?)e.Value ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@entry.Title"
                                           @onchange="e => UpdateWork(idx, entry with { Title = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                            <div class="row mb-2">
                                <div class="col-md-4">
                                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                    <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                                           @onchange="e => UpdateWork(idx, entry with { StartDate = DateTime.Parse((string?)e.Value ?? string.Empty) })" />
                                </div>
                                <div class="col-md-4">
                                    <label class="form-label">End Date</label>
                                    <input type="date" class="form-control" disabled="@entry.IsCurrent"
                                           value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                                           @onchange="e => UpdateWork(idx, entry with { EndDate = string.IsNullOrEmpty((string?)e.Value) ? null : DateTime.Parse((string)e.Value) })" />
                                </div>
                                <div class="col-md-4 d-flex align-items-end pb-2">
                                    <div class="form-check">
                                        <input type="checkbox" class="form-check-input" id="@($"current-{idx}")"
                                               checked="@entry.IsCurrent"
                                               @onchange="e => UpdateWork(idx, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                                        <label class="form-check-label" for="@($"current-{idx}")">Currently here</label>
                                    </div>
                                </div>
                            </div>
                            <div class="mb-0">
                                <label class="form-label">Description</label>
                                <textarea class="form-control" rows="2" value="@entry.Description"
                                          @onchange="e => UpdateWork(idx, entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
                            </div>
                        </div>
                    </div>
                }
                <button class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddWorkEntry">
                    + Add Another Position
                </button>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => GoToStep(1)">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromStep2">Next</button>
                </div>
            </div>
        }

        @* ── Step 3: References ── *@
        @if (_currentStep == 3)
        {
            <div>
                <h4 class="mb-3">References</h4>
                @for (int i = 0; i < _references.Count; i++)
                {
                    var idx = i;
                    var r = _references[idx];
                    <div class="card mb-3">
                        <div class="card-body">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Reference @(idx + 1)</h6>
                                @if (_references.Count > 1)
                                {
                                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                                }
                            </div>
                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Name <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@r.Name"
                                           @onchange="e => UpdateRef(idx, r with { Name = (string?)e.Value ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@r.Relationship"
                                           @onchange="e => UpdateRef(idx, r with { Relationship = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                            <div class="row">
                                <div class="col-md-6">
                                    <label class="form-label">Email <span class="text-danger">*</span></label>
                                    <input type="email" class="form-control" value="@r.Email"
                                           @onchange="e => UpdateRef(idx, r with { Email = (string?)e.Value ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                                    <input type="tel" class="form-control" value="@r.Phone"
                                           @onchange="e => UpdateRef(idx, r with { Phone = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                        </div>
                    </div>
                }
                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddReference">
                        + Add Reference
                    </button>
                }
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => GoToStep(2)">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromStep3">Next</button>
                </div>
            </div>
        }

        @* ── Step 4: Cover Letter ── *@
        @if (_currentStep == 4)
        {
            <div>
                <h4 class="mb-3">Cover Letter</h4>
                <div class="mb-2">
                    <textarea class="form-control" rows="10" maxlength="2000"
                              @bind="_coverLetter" @bind:event="oninput"></textarea>
                </div>
                <div class="text-muted small mb-3">@_coverLetter.Length / 2000 characters</div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => GoToStep(3)">Back</button>
                    <button class="btn btn-primary" @onclick="() => GoToStep(5)">Next</button>
                </div>
            </div>
        }

        @* ── Step 5: Review & Submit ── *@
        @if (_currentStep == 5)
        {
            <div>
                <h4 class="mb-3">Review &amp; Submit</h4>

                @* Personal Info Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Personal Information</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    <div class="card-body">
                        <div class="row">
                            <div class="col-md-6"><strong>Name:</strong> @_fullName</div>
                            <div class="col-md-6"><strong>Email:</strong> @_email</div>
                            <div class="col-md-6 mt-1"><strong>Phone:</strong> @_phone</div>
                            <div class="col-md-6 mt-1"><strong>Address:</strong> @_address</div>
                        </div>
                    </div>
                </div>

                @* Work History Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Work History</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    <div class="card-body">
                        @foreach (var entry in _workEntries)
                        {
                            <div class="mb-2 @(entry != _workEntries[0] ? "border-top pt-2" : "")">
                                <div><strong>@entry.Title</strong> at @entry.Company</div>
                                <div class="text-muted small">
                                    @entry.StartDate.ToString("MMM yyyy") &ndash;
                                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                                </div>
                                @if (!string.IsNullOrWhiteSpace(entry.Description))
                                {
                                    <div class="small mt-1">@entry.Description</div>
                                }
                            </div>
                        }
                    </div>
                </div>

                @* References Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>References</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <div class="card-body">
                        @foreach (var r in _references)
                        {
                            <div class="mb-2 @(r != _references[0] ? "border-top pt-2" : "")">
                                <div><strong>@r.Name</strong> (@r.Relationship)</div>
                                <div class="text-muted small">@r.Email &middot; @r.Phone</div>
                            </div>
                        }
                    </div>
                </div>

                @* Cover Letter Summary *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Cover Letter</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(4)">Edit</button>
                    </div>
                    <div class="card-body">
                        <p style="white-space: pre-wrap;">@_coverLetter</p>
                    </div>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="() => GoToStep(4)">Back</button>
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_submitting">
                        @if (_submitting)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Submit Application
                    </button>
                </div>
            </div>
        }
    }
</div>

